import {
  createContext,
  useCallback,
  useContext,
  useLayoutEffect,
  useMemo,
  useState,
} from "react";
import {
  type BuiltInTheme,
  BUILT_IN_THEMES,
  DEFAULT_THEME,
  DEFAULT_THEME_ID,
  getThemeById,
} from "@t3tools/shared/theme";

// ---------------------------------------------------------------------------
// Storage key
// ---------------------------------------------------------------------------

const STORAGE_KEY = "t3code:color-theme";

// ---------------------------------------------------------------------------
// Context
// ---------------------------------------------------------------------------

export interface ThemeContextValue {
  /** The currently active theme object. */
  readonly theme: BuiltInTheme;
  /** The currently active theme ID. */
  readonly themeId: string;
  /** Resolved dark/light value — convenience alias for `theme.isDark`. */
  readonly resolvedTheme: "dark" | "light";
  /** All available built-in themes. */
  readonly themes: readonly BuiltInTheme[];
  /** Persist and apply a new theme by ID. */
  setThemeId: (id: string) => void;
}

export const ThemeContext = createContext<ThemeContextValue | null>(null);

// ---------------------------------------------------------------------------
// DOM helpers — run immediately on module load for flash prevention
// ---------------------------------------------------------------------------

function readStoredThemeId(): string {
  try {
    const stored = localStorage.getItem(STORAGE_KEY);
    if (stored && BUILT_IN_THEMES.some((t) => t.id === stored)) return stored;
  } catch {
    // localStorage unavailable (e.g. private-browsing restrictions)
  }
  return DEFAULT_THEME_ID;
}

/**
 * Applies a theme's color values as inline CSS custom properties on the root
 * element and toggles the `.dark` class. Inline styles win over class-based
 * CSS rules, so this cleanly overrides Tailwind's built-in light/dark palette.
 */
export function applyThemeToDOM(theme: BuiltInTheme): void {
  const root = document.documentElement;
  const { colors, isDark } = theme;

  // Core design-token overrides (consumed by all Tailwind bg-*/text-* utilities)
  root.style.setProperty("--background", colors.background);
  root.style.setProperty("--foreground", colors.foreground);
  root.style.setProperty("--primary", colors.accent);
  root.style.setProperty("--ring", colors.accent);
  root.style.setProperty("--card", colors.card);
  root.style.setProperty("--border", colors.border);

  // Surface-specific custom properties (available for theme-aware components)
  root.style.setProperty("--theme-sidebar-bg", colors.sidebarBackground);
  root.style.setProperty("--theme-sidebar-border", colors.sidebarBorder);
  root.style.setProperty("--theme-editor-bg", colors.editorBackground);
  root.style.setProperty("--theme-editor-gutter", colors.editorGutter);
  root.style.setProperty("--theme-terminal-bg", colors.terminalBackground);
  root.style.setProperty("--theme-terminal-fg", colors.terminalForeground);
  root.style.setProperty("--theme-terminal-cursor", colors.terminalCursor);
  root.style.setProperty("--theme-statusbar-bg", colors.statusBarBackground);
  root.style.setProperty("--theme-statusbar-fg", colors.statusBarForeground);

  // Drive Tailwind's `dark:` variant via the `.dark` class
  root.classList.toggle("dark", isDark);
}

// Apply immediately to prevent a flash of the un-themed default palette
if (typeof document !== "undefined") {
  applyThemeToDOM(getThemeById(readStoredThemeId()));
}

// ---------------------------------------------------------------------------
// Provider
// ---------------------------------------------------------------------------

export function ThemeProvider({ children }: { children: React.ReactNode }) {
  const [themeId, setThemeIdState] = useState<string>(readStoredThemeId);
  const theme = useMemo(() => getThemeById(themeId), [themeId]);

  const setThemeId = useCallback((id: string) => {
    const next = getThemeById(id);
    try {
      localStorage.setItem(STORAGE_KEY, id);
    } catch {
      // Best-effort persistence
    }
    applyThemeToDOM(next);
    setThemeIdState(id);
  }, []);

  // Re-apply on every render cycle where the theme changed and on initial mount,
  // ensuring the DOM stays in sync even after hot-module replacement or hydration.
  useLayoutEffect(() => {
    applyThemeToDOM(theme);
  }, [theme]);

  const value = useMemo<ThemeContextValue>(
    () => ({
      theme,
      themeId,
      resolvedTheme: theme.isDark ? "dark" : "light",
      themes: BUILT_IN_THEMES,
      setThemeId,
    }),
    [theme, themeId, setThemeId],
  );

  return <ThemeContext.Provider value={value}>{children}</ThemeContext.Provider>;
}

// ---------------------------------------------------------------------------
// Fallback value used by useColorTheme outside a provider (SSR / tests)
// ---------------------------------------------------------------------------

const FALLBACK_CONTEXT: ThemeContextValue = {
  theme: DEFAULT_THEME,
  themeId: DEFAULT_THEME_ID,
  resolvedTheme: "dark",
  themes: BUILT_IN_THEMES,
  setThemeId: () => undefined,
};

/**
 * Returns the active color theme and a setter.
 * Must be called inside a `<ThemeProvider>` in the React tree.
 */
export function useColorTheme(): ThemeContextValue {
  return useContext(ThemeContext) ?? FALLBACK_CONTEXT;
}

