                        aria-label={
                          isConnecting
                            ? "Connecting"
                            : isPreparingWorktree
                              ? "Preparing worktree"
                              : isSendBusy
                                ? "Sending"
                                : "Send message"
                        }
                      >
                        {isConnecting || isSendBusy ? (
                          <svg
                            width="14"
                            height="14"
                            viewBox="0 0 14 14"
                            fill="none"
                            className="animate-spin"
