import { CheckIcon } from "lucide-react";
import type { BuiltInTheme } from "@t3tools/shared/theme";
import { useColorTheme } from "~/hooks/useColorTheme";

// ---------------------------------------------------------------------------
// ThemeSelector
// ---------------------------------------------------------------------------

/**
 * Renders a grid of theme cards, each with a mini UI preview and label.
 * Selecting a card immediately applies and persists the theme.
 */
export function ThemeSelector() {
  const { themeId, setThemeId, themes } = useColorTheme();

  return (
    <div className="flex flex-wrap gap-3" role="radiogroup" aria-label="Color theme">
      {themes.map((theme) => (
        <ThemeCard
          key={theme.id}
          theme={theme}
          selected={themeId === theme.id}
          onSelect={() => setThemeId(theme.id)}
        />
      ))}
    </div>
  );
}

// ---------------------------------------------------------------------------
// ThemeCard
// ---------------------------------------------------------------------------

interface ThemeCardProps {
  theme: BuiltInTheme;
  selected: boolean;
  onSelect: () => void;
}

function ThemeCard({ theme, selected, onSelect }: ThemeCardProps) {
  return (
    <button
      type="button"
      role="radio"
      aria-checked={selected}
      onClick={onSelect}
      className={[
        "relative flex flex-col gap-2 rounded-xl border p-2.5 text-left transition-colors",
        "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring",
        selected
          ? "border-primary/60 bg-primary/8"
          : "border-border bg-background hover:bg-accent",
      ].join(" ")}
    >
      <ThemePreview theme={theme} />

      <div className="flex items-center justify-between gap-2 px-0.5">
        <span className="text-xs font-medium text-foreground">{theme.label}</span>

        {selected ? (
          <span
            className="flex h-4 w-4 items-center justify-center rounded-full"
            style={{ background: theme.colors.accent }}
            aria-hidden="true"
          >
            <CheckIcon className="h-2.5 w-2.5 text-white" strokeWidth={3} />
          </span>
        ) : null}
      </div>
    </button>
  );
}

// ---------------------------------------------------------------------------
// ThemePreview — mini-UI illustration built entirely from theme color values
// ---------------------------------------------------------------------------

interface ThemePreviewProps {
  theme: BuiltInTheme;
}

function ThemePreview({ theme }: ThemePreviewProps) {
  const { colors } = theme;

  return (
    <div
      className="relative h-16 w-28 overflow-hidden rounded-lg"
      style={{ background: colors.background }}
      aria-hidden="true"
    >
      {/* Sidebar strip */}
      <div
        className="absolute inset-y-0 left-0 w-6"
        style={{
          background: colors.sidebarBackground,
          borderRight: `1px solid ${colors.sidebarBorder}`,
        }}
      >
        {/* Sidebar nav dots */}
        <div className="flex flex-col gap-1.5 p-1.5 pt-2">
          {[0.5, 0.3, 0.2].map((opacity, i) => (
            <div
              key={i}
              className="h-1 w-3 rounded-full"
              style={{ background: colors.foreground, opacity }}
            />
          ))}
        </div>
      </div>

      {/* Status bar */}
      <div
        className="absolute inset-x-0 bottom-0 h-2.5"
        style={{ background: colors.statusBarBackground }}
      >
        {/* Status bar text dots */}
        <div className="flex items-center gap-1 px-1.5 h-full">
          <div
            className="h-1 w-4 rounded-full"
            style={{ background: colors.statusBarForeground, opacity: 0.8 }}
          />
          <div
            className="h-1 w-2.5 rounded-full"
            style={{ background: colors.statusBarForeground, opacity: 0.5 }}
          />
        </div>
      </div>

      {/* Editor area */}
      <div
        className="absolute bottom-2.5 left-6 right-0 top-0"
        style={{ background: colors.editorBackground }}
      >
        {/* Gutter strip */}
        <div
          className="absolute inset-y-0 left-0 w-3"
          style={{ background: colors.editorGutter }}
        />

        {/* Simulated code lines */}
        <div className="absolute inset-y-0 left-3 right-0 flex flex-col justify-center gap-1.5 px-2 py-2">
          <div
            className="h-1.5 rounded-full"
            style={{ background: colors.accent, opacity: 0.85, width: "55%" }}
          />
          <div
            className="h-1.5 rounded-full"
            style={{ background: colors.foreground, opacity: 0.5, width: "70%" }}
          />
          <div
            className="h-1.5 rounded-full"
            style={{ background: colors.foreground, opacity: 0.3, width: "40%" }}
          />
        </div>
      </div>

      {/* Accent dot — top-right corner */}
      <div
        className="absolute right-1.5 top-1.5 h-2 w-2 rounded-full ring-1 ring-white/10"
        style={{ background: colors.accent }}
      />
    </div>
  );
}

